  }, [history]);

  useEffect(() => {
    localStorage.setItem('aviator_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('aviator_mode', mode);
  }, [mode]);

  useEffect(() => {
    localStorage.setItem('aviator_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
