  const handleGetSignal = useCallback(async () => {
    if (status !== AppStatus.IDLE || countdown !== null) return;

    audioService.playScanStart();
    setStatus(AppStatus.LOADING);
    setShowNotifications(false); 

    try {
      const data = await getPrediction(mode);
