      setTimeout(() => {
        setReliability(98.5 + (Math.random() * 1.0 - 0.5));

        const newHistoryItem: HistoryItem = { 
          id: `h-${Date.now()}`,
          val: data.multiplier, 
          time: data.timestamp,
          hash: generateHash(),
          verified: true
        };
