                   <Target size={16} className="text-emerald-500" />
                </div>
                <div>
                   <div className={`text-[7px] font-black uppercase tracking-widest ${theme === 'dark' ? 'text-white/30' : 'text-slate-400'}`}>{t.avgSignal}</div>
