import { GoogleGenAI, Type } from "@google/genai";
import { Prediction, PredictionMode } from "../types";

/**
 * يقوم بجلب رقم التوقع التالي من Firebase ريل تايم من المسار pre/hipr/hipr
 */
export const getPrediction = async (mode: PredictionMode = PredictionMode.BALANCED): Promise<Prediction> => {
  // المسار المطلوب: pre/hipr/hipr
  const FIREBASE_URL = "https://crazy-12-default-rtdb.firebaseio.com/pre/hipr/hipr.json";

  try {
    const fbResponse = await fetch(FIREBASE_URL, {
      method: 'GET',
      headers: { 'Accept': 'application/json' },
      cache: 'no-cache'
    });

    if (fbResponse.ok) {
      const data = await fbResponse.json();
      let multiplierValue: number | null = null;

      // التعامل مع البيانات سواء كانت رقماً مباشراً أو كائناً
      if (typeof data === 'number') {
        multiplierValue = data;
      } else if (data && typeof data === 'object') {
        // في حال كان الهيكل يحتوي على مفاتيح فرعية
        if (typeof data.hipr === 'number') multiplierValue = data.hipr;
        else if (typeof data.value === 'number') multiplierValue = data.value;
        else if (typeof data.multiplier === 'number') multiplierValue = data.multiplier;
        else {
            // محاولة جلب أول قيمة رقمية موجودة في الكائن
            const firstNum = Object.values(data).find(v => typeof v === 'number') as number | undefined;
            if (firstNum !== undefined) multiplierValue = firstNum;
        }
      }

      if (multiplierValue !== null && !isNaN(multiplierValue)) {
        const confBase = mode === PredictionMode.STABLE ? 0.99 : mode === PredictionMode.HIGH_RISK ? 0.85 : 0.95;

        return {
          multiplier: parseFloat(multiplierValue.toFixed(2)),
          confidence: confBase,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }),
        };
      }
    }
    throw new Error("Fallback to AI");
  } catch (fbError) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let promptText = "Generate a realistic Aviator game multiplier prediction. Return JSON only.";
    let thinkingBudget = 0;

    if (mode === PredictionMode.STABLE) {
      promptText = "Generate a SAFE Aviator multiplier (1.1 to 1.8). Return JSON only.";
    } else if (mode === PredictionMode.HIGH_RISK) {
      promptText = "Generate a HIGH RISK Aviator multiplier (2.5 to 10.0). Return JSON only.";
    } else if (mode === PredictionMode.AI_PRO) {
      promptText = "Analyze recent simulated trends and generate a HIGH CONFIDENCE multiplier prediction. Return JSON only.";
      thinkingBudget = 1000;
    }

    try {
      const response = await ai.models.generateContent({
        model: mode === PredictionMode.AI_PRO ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptText }] }],
        config: {
          responseMimeType: "application/json",
          thinkingConfig: thinkingBudget > 0 ? { thinkingBudget } : undefined,
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              multiplier: { type: Type.NUMBER },
              confidence: { type: Type.NUMBER },
            },
            required: ['multiplier', 'confidence'],
          },
        },
      });

      const aiData = JSON.parse(response.text || '{}');

      return {
        multiplier: aiData.multiplier || 1.5,
        confidence: aiData.confidence || 0.95,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }),
      };
    } catch (error) {
      return {
        multiplier: parseFloat((Math.random() * 1.5 + 1.1).toFixed(2)),
        confidence: 0.90,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }),
      };
    }
  }
};

