  const sortedHistory = useMemo(() => {
    let result = [...history];
    if (sortMode === 'multiplier') {
      result.sort((a, b) => b.val - a.val);
    } else {
      // For 'recent', history is naturally newest first, but we ensure it by sorting by time/id
      result.sort((a, b) => b.id.localeCompare(a.id));
